        {
          "id": "f2",
          "description": "package_files in the contract summary uses bare filenames ('agent-role-builder-role.md') without a path, making promotion target ambiguous",
          "source_section": "Contract summary / package_files"
        }
      ],
      "redesign_guidance": "Prefix every canonical artifact entry in <outputs> with its canonical directory root: 'tools/agent-role-builder/role/<slug>-role.md', etc. Mirror those full paths in contract.package_files. This will silence all four MISSING_REQUIRED_OUTPUT self-check errors."
    },
    {
      "id": "group-2",
      "summary": "Duplicate 'Application workflow creation' and 'Application runtime orchestration' lines in <scope> Not-in-scope block introduce internal contradiction with the in-scope carve-out for board-review orchestration",
